+    [EventSubscriber(ObjectType::Table, Database::"Whse. Worksheet Line", 'OnBeforeCalcAvailableQtyBase', '', false, false)]
+    local procedure OnBeforeCalcAvailableQtyBase(var WhseWorksheetLine: Record "Whse. Worksheet Line"; var AvailableQty: Decimal; var IsHandled: Boolean)
+    var
+        WarehouseAvailabilityMgt: Codeunit "Warehouse Availability Mgt.";
+        Location: Record Location;
+    begin
+        if WhseWorksheetLine."Source Type" <> Database::"Prod. Order Component" then
