+
+        AvailableQty :=
+            WarehouseAvailabilityMgt.CalcQtyAvailToTakeOnWhseWorksheetLine(WhseWorksheetLine) -
+            WarehouseAvailabilityMgt.CalcQtyAssgndOnWksh(WhseWorksheetLine, true, true) +
