+    local procedure CalcAssignedQtyOnReservedNotOnILELines(WhseWorksheetLine: Record "Whse. Worksheet Line"): Decimal
+    var
+        RelatedWhseWorksheetLine: Record "Whse. Worksheet Line";
+        AssignedReservedQtyBase: Decimal;
+        ReservedNotOnILEQtyBase: Decimal;
+    begin
+        AssignedReservedQtyBase := CalcReservedQtyNotOnILEForLine(WhseWorksheetLine);
+
+        RelatedWhseWorksheetLine.SetCurrentKey("Item No.", "Location Code", "Worksheet Template Name", "Variant Code");
+        RelatedWhseWorksheetLine.SetRange("Item No.", WhseWorksheetLine."Item No.");
+        RelatedWhseWorksheetLine.SetRange("Location Code", WhseWorksheetLine."Location Code");
+        RelatedWhseWorksheetLine.SetRange("Worksheet Template Name", WhseWorksheetLine."Worksheet Template Name");
+        RelatedWhseWorksheetLine.SetRange("Variant Code", WhseWorksheetLine."Variant Code");
+        if RelatedWhseWorksheetLine.FindSet() then
+            repeat
+                if RelatedWhseWorksheetLine.RecordId <> WhseWorksheetLine.RecordId then begin
+                    ReservedNotOnILEQtyBase := CalcReservedQtyNotOnILEForLine(RelatedWhseWorksheetLine);
+                    if ReservedNotOnILEQtyBase > 0 then
+                        if ReservedNotOnILEQtyBase <= RelatedWhseWorksheetLine."Qty. to Handle (Base)" then
+                            AssignedReservedQtyBase += ReservedNotOnILEQtyBase
+                        else
+                            AssignedReservedQtyBase += RelatedWhseWorksheetLine."Qty. to Handle (Base)";
+                end;
+            until RelatedWhseWorksheetLine.Next() = 0;
+
+        exit(AssignedReservedQtyBase);
+    end;
