+            WhseWorksheetLine."Source No.",
+            WhseWorksheetLine."Source Line No.",
+            WhseWorksheetLine."Source Subline No.");
+        if ReservationEntry.FindSet() then
+            repeat
+                ReservedNotOnILEQtyBase += CreatePick.CalcQtyResvdNotOnILE(ReservationEntry."Entry No.", ReservationEntry.Positive);
+            until ReservationEntry.Next() = 0;
